def merge_ranges(pairs):
    pairs.sort(key=lambda x: x[0])  # Sort by start time
    merged = []
    for pair in pairs:
        if not merged or merged[-1][1] < pair[0]:
            merged.append(pair)
        else:
            merged[-1][1] = max(merged[-1][1], pair[1])
    return merged
